"use strict";parserFactory.register("mandarinducktales.com",()=>new MandarinducktalesParser);class MandarinducktalesParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll(".wp-container-10 p a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector(".wp-container-10")}extractTitleImpl(e){return e.querySelector("h1")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".wp-container-10")]}}